return [{
  json: {
    url: 'https://www.nasa.gov/wp-content/uploads/2023/09/nsn-llcd-1.mp4',
    data_class: 'D0',
    slug: 'n8n-manual-nasa',
    max_cost_eur: '0.30',
    note: 'Edit this Code node for the next single-video manual run.'
  }
}];

const result = items[0].json;

if (!result.ok) {
  return [{
    json: {
      status: 'error',
      url: result.url,
      data_class: result.data_class,
      error: result.error || result.raw || 'Unknown pipeline error',
      log_file: result.log_file_windows || result.log_file,
      bridge_exit_code: result.bridge_exit_code,
    }
  }];
}

return [{
  json: {
    status: 'success',
    url: result.url,
    data_class: result.data_class,
    slug: result.slug,
    analysis_markdown: result.files.analysis_markdown_windows,
    analysis_json: result.files.analysis_json_windows,
    transcript_txt: result.files.transcript_txt_windows,
    video_file: result.files.video_windows,
    audio_file: result.files.audio_windows,
    log_file: result.log_file_windows,
    cost_usd_estimated: result.cost.estimated_actual_usd,
    preflight_cost_usd: result.cost.preflight_usd,
    tokens: result.cost.usage,
    steps_seconds: result.steps,
    finished_at: result.finished_at,
  }
}];
